/* Enables SharedArrayBuffer on GitHub Pages via COOP/COEP headers */
;(()=>{const n="coi-serviceworker";if(self.document===undefined){self.addEventListener("install",()=>self.skipWaiting());self.addEventListener("activate",n=>n.waitUntil(self.clients.claim()));self.addEventListener("fetch",n=>{const e=n.request;if(e.cache==="only-if-cached"&&e.mode!=="same-origin")return;n.respondWith(fetch(e).then(n=>{if(n.status===0)return n;const e=new Headers(n.headers);e.set("Cross-Origin-Opener-Policy","same-origin");e.set("Cross-Origin-Embedder-Policy","require-corp");return new Response(n.body,{status:n.status,statusText:n.statusText,headers:e})}).catch(()=>fetch(e)))});return}if(localStorage.getItem(n))return;if(!window.crossOriginIsolated){const e=new Promise(n=>navigator.serviceWorker.addEventListener("controllerchange",n));navigator.serviceWorker.register(window.document.currentScript.src).then(n=>{if(n.active)return;return e}).then(()=>location.reload());return}const e=localStorage.getItem(n+"_reason");if(e){console.log("[coi] Reason:",e);localStorage.removeItem(n+"_reason")};localStorage.setItem(n,1)})();
